package com.example.loggingapi.controller;

import com.example.loggingapi.model.ApiResponse;
import com.example.loggingapi.service.MessageService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/messages")
public class MessageController {

    private static final Logger logger = LoggerFactory.getLogger(MessageController.class);

    private final MessageService messageService;

    public MessageController(MessageService messageService) {
        this.messageService = messageService;
    }

    @GetMapping
    public ResponseEntity<ApiResponse> getMessage() {
        logger.info("Received request to fetch default message");
        String message = messageService.getDefaultMessage();
        logger.info("Successfully fetched default message");
        return ResponseEntity.ok(new ApiResponse("success", message));
    }

    @PostMapping
    public ResponseEntity<ApiResponse> createMessage(@RequestParam String value) {
        logger.info("Received request to create message");
        String createdMessage = messageService.createMessage(value);
        logger.info("Successfully created message");
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(new ApiResponse("success", createdMessage));
    }
}

